    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0xB93BC454786332D5ULL + 0xC6A43030351452C9ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0x9FC002233A0D5935ULL + 0x92A9F3171D062FBDULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xECA7F23EB4CD894FULL + 0xDBEBF0A96A4B2A9CULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xE4CA5C5004A025E7ULL + 0xDC785299E29D8D1DULL);
