    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xC39CDF79B67BCE65ULL + 0xB222F4025F278497ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseB(pNonce * 0xFF1D9B1E7E9061DDULL + 0xCE1DE77AA37D50CEULL);
