            aScatter = TwistMix64::DiffuseC(((aScatter ^ aDomainWordScatter) ^ aNonceWordG));
            //
            aOrbiterJ = ((aWandererA + RotL64(aScatter, 60U)) + 14249093584376402677U) + aNonceWordP;
