            aOrbiterH = RotL64((aOrbiterH * 10948288997163592463U), 27U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterA) + 10748158733051120339U) + aNonceWordI;
            aOrbiterD = (aOrbiterD ^ aOrbiterE) ^ 2467801787989056455U;
            aOrbiterD = RotL64((aOrbiterD * 12621934274702358977U), 29U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterF) + 9244415080474351390U;
            aOrbiterI = (aOrbiterI ^ aOrbiterH) ^ 8517784887959492079U;
            aOrbiterI = RotL64((aOrbiterI * 17022899813765884147U), 41U);
            //
            aOrbiterD = (((aOrbiterD + aOrbiterH) + 8409307332803038455U) + aOrbiterUpdateSaltA[((aIndex + 23U)) & S_SALT1]) + aNonceWordD;
            aOrbiterK = ((aOrbiterK ^ aOrbiterD) ^ 11043806021873232950U) ^ aOrbiterUpdateSaltF[(((31U - aIndex) + 24U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 8294888329708842989U), 51U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterK) + 17512395828450251457U;
            aOrbiterE = (aOrbiterE ^ aOrbiterG) ^ 16849067939795823992U;
