            //
            aOrbiterF = ((aOrbiterF + aOrbiterG) + 78307505705383302U) + aOrbiterUpdateSaltB[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterF) ^ 4834528975263832983U;
