            aIngress = aIngress + (aOrbiterB ^ RotL64(aOrbiterJ, 37U));
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterD, 40U));
            aIngress = aIngress + (aOrbiterA ^ RotL64(aOrbiterC, 21U));
            aIngress = aIngress + RotL64(aOrbiterG, 35U);
            aIngress = TwistMix64::DiffuseB((aIngress + aScatter));
            //
            aWandererC = aWandererC ^ ((RotL64(aCross, 11U) + aOrbiterI) + RotL64(aOrbiterC, 51U));
            aWandererB = aWandererB + (((RotL64(aIngress, 51U) + aOrbiterD) + RotL64(aOrbiterG, 13U)) + aWandererUpdateSaltE[((aIndex + 22U)) & S_SALT1]);
            aWandererG = aWandererG ^ (((RotL64(aPrevious, 30U) + RotL64(aOrbiterJ, 29U)) + aOrbiterB) + aNonceWordK);
            aWandererE = aWandererE + ((RotL64(aScatter, 41U) + RotL64(aOrbiterK, 26U)) + aOrbiterI);
